    buf.append(product.getUnderlyingIndex().getBuySell());
    buf.append(' ');
    buf.append(SummarizerUtils.amount(product.getUnderlyingIndex().getCurrency(), product.getUnderlyingIndex().getNotional()));
    buf.append(" TRANCHE ");
    buf.append(SummarizerUtils.percent(product.getAttachmentPoint()));
    buf.append('-');
    buf.append(SummarizerUtils.percent(product.getDetachmentPoint()));
    buf.append(" / ");
    buf.append(SummarizerUtils.percent(product.getUnderlyingIndex().getFixedRate()));
    buf.append(" : ");
    buf.append(SummarizerUtils.dateRange(paymentSchedule.getStartDate(), paymentSchedule.getEndDate()));
