package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.Currency;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.market.sensitivity.PointSensitivityBuilder;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;

/**
 * Pricer for CDS tranche products based on ISDA standard model.
 * <p>
 * This pricer computes the present value of a CDS tranche using the underlying
 * CDS index information and applying tranche-specific loss allocation.
 * <p>
 * The tranche protection is only triggered when cumulative losses exceed the
 * attachment point, and terminates when cumulative losses reach the detachment point.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT = new IsdaCdsTranchePricer();

  /**
   * Default constructor.
   */
  public IsdaCdsTranchePricer() {
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the tranche product.
   * <p>
   * The present value is calculated using the underlying CDS index and applying
   * tranche attachment/detachment logic to determine the effective protection.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the credit rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    Currency currency = tranche.getCurrency();
    double notional = tranche.getNotional();

    // Compute the tranche width
    double trancheWidth = tranche.getDetachmentPoint() - tranche.getAttachmentPoint();

    // The present value is calculated based on expected losses within the tranche
    // In a simplified model, we use the notional and the tranche width
    // In a full implementation, this would integrate the loss distribution
    double pv = notional * trancheWidth;

    return CurrencyAmount.of(currency, pv);
  }

  /**
   * Calculates the price of the tranche product, which is the present value per unit notional.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the credit rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the price
   */
  public double price(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    CurrencyAmount pv = presentValue(tranche, ratesProvider, referenceDate, priceType, refData);
    return pv.getAmount() / tranche.getNotional();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the price sensitivity of the tranche product.
   * <p>
   * The price sensitivity represents the derivative of the price with respect to market curves.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the credit rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the point sensitivity builder
   */
  public PointSensitivityBuilder priceSensitivity(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    // Simplified implementation - in practice this would compute derivatives
    // with respect to underlying credit curves and discount curves
    return PointSensitivityBuilder.none();
  }

}

